package main

import "fmt"

// transpose returns the transpose of a rectangular matrix (rows<->cols).
func transpose(m [][]int) [][]int {
	if len(m) == 0 {
		return nil
	}
	rows, cols := len(m), len(m[0])
	out := make([][]int, cols)
	for i := range out {
		out[i] = make([]int, rows)
		for j := 0; j < rows; j++ {
			out[i][j] = m[j][i]
		}
	}
	return out
}

func main() {
	m := [][]int{
		{1, 2, 3},
		{4, 5, 6},
	}
	fmt.Println(transpose(m)) // [[1 4] [2 5] [3 6]]
}
```

