		counts[n]++
		if counts[n] > count {
			value, count = n, counts[n]
		}
	}
	return value, count
}

func main() {
	v, c := mostFrequent([]int{1, 3, 3, 2, 3, 1})
	fmt.Printf("%d appears %d times\n", v, c)
}
