func joinCSV(words []string) string {
	var b strings.Builder
	for i, w := range words {
		if i > 0 {
			b.WriteByte(',')
		}
		b.WriteString(w)
	}
	return b.String()
}

func main() {
	fmt.Println(joinCSV([]string{"alpha", "beta", "gamma"}))
}
```

